var apiResp = $input.first().json;
var dbData = $('Status: Lookup DB').first().json;
var senderPhone = $('Normalize Command').item.json.senderPhone;

var status = apiResp.status || apiResp.state || "";
if (apiResp.data) status = apiResp.data.status || apiResp.data.state || status;
if (apiResp.instance) status = apiResp.instance.status || apiResp.instance.state || status;

var emoji = "⚪";
if (status === "connected") emoji = "🟢";
else if (status === "connecting") emoji = "🟡";
else if (status === "disconnected") emoji = "🔴";

var msg = emoji + " *Status da Instância*\n\n";
msg += "📛 Nome: " + (dbData.instance_name || "N/A") + "\n";
msg += "📊 Status: " + (status || "desconhecido") + "\n";

if (dbData.disconnected_at) {
  msg += "⏰ Última desconexão: " + dbData.disconnected_at + "\n";
}
if (dbData.disconnect_reason) {
  msg += "📝 Motivo: " + dbData.disconnect_reason + "\n";
}

msg += "\n_Comandos: /criar | /reconectar | /conectar | /excluir | /status_";

return [{
  json: {
    senderPhone: senderPhone,
    text: msg
  }
}];

var items = $input.all();
var apiInstances = $('Get All Instances').first().json;
var dbInstances = $('Get DB Connected').all().map(function(item) { return item.json; });

// API pode retornar array direto ou dentro de um campo
var apiList = [];
if (Array.isArray(apiInstances)) {
  apiList = apiInstances;
} else if (apiInstances.data && Array.isArray(apiInstances.data)) {
  apiList = apiInstances.data;
} else if (apiInstances.instances && Array.isArray(apiInstances.instances)) {
  apiList = apiInstances.instances;
} else {
  // Tenta pegar todos os items do nó
  apiList = $('Get All Instances').all().map(function(item) { return item.json; });
}

// Monta mapa: token ou name → status da API
var apiStatusMap = {};
for (var i = 0; i < apiList.length; i++) {
  var inst = apiList[i];
  var key = inst.token || inst.name || inst.id || "";
  var st = inst.status || inst.state || "";
  if (inst.instance) st = inst.instance.status || inst.instance.state || st;
  apiStatusMap[key] = st;
  // Também mapeia por name
  if (inst.name) apiStatusMap[inst.name] = st;
  if (inst.id) apiStatusMap[String(inst.id)] = st;
}

// Compara: instâncias que no DB são 'connected' mas na API não são
var disconnected = [];
for (var j = 0; j < dbInstances.length; j++) {
  var db = dbInstances[j];
  var apiStatus = apiStatusMap[db.instance_token] || apiStatusMap[db.instance_name] || apiStatusMap[db.instance_id] || "unknown";

  if (apiStatus !== "connected") {
    disconnected.push({
      phone_cliente: db.phone_cliente,
      instance_name: db.instance_name,
      instance_id: db.instance_id,
      db_status: db.status,
      api_status: apiStatus
    });
  }
}

if (disconnected.length === 0) {
  return [{ json: { hasDisconnected: false, count: 0 } }];
}

return disconnected.map(function(d) {
  d.hasDisconnected = true;
  d.count = disconnected.length;
  return { json: d };
});

var items = $input.all();
var lines = [];
for (var i = 0; i < items.length; i++) {
  var d = items[i].json;
  lines.push("• " + (d.instance_name || "N/A") + " (cliente: " + (d.phone_cliente || "N/A") + ") → " + (d.api_status || "unknown"));
}

var msg = "🚨 *ALERTA: Instância(s) Desconectada(s)*\n\n";
msg += lines.join("\n");
msg += "\n\n_Detectado pelo monitor automático_";

return [{
  json: {
    adminPhone: "5585999717430",
    text: msg
  }
}];

var apiInstances = $('Get All Instances').first().json;
var apiList = [];
if (Array.isArray(apiInstances)) {
  apiList = apiInstances;
} else if (apiInstances.data && Array.isArray(apiInstances.data)) {
  apiList = apiInstances.data;
} else if (apiInstances.instances && Array.isArray(apiInstances.instances)) {
  apiList = apiInstances.instances;
} else {
  apiList = $('Get All Instances').all().map(function(item) { return item.json; });
}

// Atualiza instâncias que estão conectadas na API
var connected = [];
for (var i = 0; i < apiList.length; i++) {
  var inst = apiList[i];
  var st = inst.status || inst.state || "";
  if (inst.instance) st = inst.instance.status || inst.instance.state || st;
  if (st === "connected") {
    connected.push({
      name: inst.name || "",
      token: inst.token || "",
      id: inst.id || ""
    });
  }
}

if (connected.length === 0) {
  return [{ json: { noUpdates: true } }];
}

return connected.map(function(c) {
  return { json: c };
});
